import React, { useState } from 'react';

const Marketplace = () => {
  const [selectedCategory, setSelectedCategory] = useState(null);
  const categories = ["Academic Projects", "Assignments", "Notes & Resources"];

  return (
    <div style={{ background: '#000', color: '#fff', padding: '50px', minHeight: '100vh', textAlign: 'center' }}>
      <h1>Explore Marketplace</h1>
      <p style={{ color: '#888' }}>Select a category to view available items</p>
      
      <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', marginTop: '30px' }}>
        {categories.map((cat) => (
          <div 
            key={cat}
            onClick={() => setSelectedCategory(cat)}
            style={{
              background: '#111', padding: '30px', borderRadius: '15px', 
              cursor: 'pointer', border: selectedCategory === cat ? '1px solid #00d2ff' : '1px solid #333',
              minWidth: '200px', transition: '0.3s'
            }}
          >
            {cat}
          </div>
        ))}
      </div>

      {selectedCategory && (
        <div style={{ marginTop: '50px' }}>
          <h2 style={{ color: '#00d2ff' }}>Showing items for: {selectedCategory}</h2>
          <p>No items found in this category yet.</p>
        </div>
      )}
    </div>
  );
};

export default Marketplace;
